//! Karmic attention regulator — Lucas/Fibonacci shell from `Gnosis.KarmicAttentionOptimizer`.
//!
//! After `UniversalIntelligenceSSMClosure` admits head pruning, this module refines *which*
//! dormant heads may be dropped: heads whose `(opportunity_k, waste_q)` ledger sits on the
//! Δ=5 Pell shell (defect ≤ ε) are **protected**; high-defect heads remain prunable.

pub const GOLDEN_DISCRIMINANT: i64 = 5;

pub const KARMIC_MESH_RESIDUAL_VANISHES_THEOREM: &str =
    "Gnosis.KarmicAttentionOptimizer.meshResidualNat_self";

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct HeadQkLedger {
    pub layer_index: usize,
    pub head_index: usize,
    pub waste_q: i64,
    pub opportunity_k: i64,
}

#[inline]
fn mesh_law_side(layer_index: usize) -> i128 {
    if layer_index.is_multiple_of(2) {
        4
    } else {
        -4
    }
}

#[inline]
pub fn mesh_form(opportunity_k: i64, waste_q: i64) -> i128 {
    let l = opportunity_k as i128;
    let f = waste_q as i128;
    l * l - GOLDEN_DISCRIMINANT as i128 * f * f
}

/// Absolute defect from the legal shell `L² - 5·F² ∈ {±4}` at this layer parity.
pub fn mesh_residual_nat(opportunity_k: i64, waste_q: i64, layer_index: usize) -> u128 {
    let target = mesh_law_side(layer_index);
    let d = mesh_form(opportunity_k, waste_q) - target;
    d.unsigned_abs()
}

#[inline]
pub fn head_mesh_residual(ledger: &HeadQkLedger) -> u128 {
    mesh_residual_nat(ledger.opportunity_k, ledger.waste_q, ledger.layer_index)
}

/// Head keys (`layer:head`) with defect **strictly greater** than `epsilon` — candidates
/// to treat as karmically unstable (off-shell).
pub fn karmic_prune_head_keys(epsilon: u128, ledgers: &[HeadQkLedger]) -> Vec<String> {
    ledgers
        .iter()
        .filter(|h| head_mesh_residual(h) > epsilon)
        .map(|h| format!("{}:{}", h.layer_index, h.head_index))
        .collect()
}

/// Refine a herd-learned dormant set: drop keys that are on-shell (defect ≤ ε) when a
/// ledger row exists. Keys without ledger rows are kept (herd signal still applies).
pub fn refine_dormant_heads_with_karmic_shell(
    dormant_keys: &[String],
    ledgers: &[HeadQkLedger],
    epsilon: u128,
) -> Vec<String> {
    use std::collections::HashMap;

    let mut owned: HashMap<String, &HeadQkLedger> = HashMap::new();
    for row in ledgers {
        owned.insert(format!("{}:{}", row.layer_index, row.head_index), row);
    }

    let mut out = Vec::new();
    for key in dormant_keys {
        match owned.get(key.as_str()) {
            Some(row) => {
                if head_mesh_residual(row) > epsilon {
                    out.push(key.clone());
                }
            }
            None => out.push(key.clone()),
        }
    }
    out
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn lucas_fib_witness_layer_zero_is_shell() {
        // lucas 4 = 7, fib 4 = 3 → 49 - 5·9 = 4 (even index target 4)
        let row = HeadQkLedger {
            layer_index: 0,
            head_index: 0,
            waste_q: 3,
            opportunity_k: 7,
        };
        assert_eq!(head_mesh_residual(&row), 0);
    }

    #[test]
    fn off_shell_has_positive_defect() {
        let row = HeadQkLedger {
            layer_index: 0,
            head_index: 0,
            waste_q: 1,
            opportunity_k: 1,
        };
        assert!(head_mesh_residual(&row) > 0);
    }

    #[test]
    fn refine_protects_on_shell_head() {
        let ledgers = vec![HeadQkLedger {
            layer_index: 0,
            head_index: 1,
            waste_q: 3,
            opportunity_k: 7,
        }];
        let dormant = vec!["0:1".to_string(), "0:3".to_string()];
        let refined = refine_dormant_heads_with_karmic_shell(&dormant, &ledgers, 0);
        assert_eq!(refined, vec!["0:3".to_string()]);
    }
}
